-- Tab System Functions
local function Tab_Main_window_SetVisible(visible)
    if Main_window then Main_window.Visible = visible end
    if Title then
        Title.Visible = visible
    end
    if Title_Background then
        Title_Background.Visible = visible
    end
    if Pickaxe then
        Pickaxe.Visible = visible
    end
    if Pickaxe_Selection then
        Pickaxe_Selection.Visible = visible
        if Pickaxe_Selection_Text then Pickaxe_Selection_Text.Visible = visible end
        if Pickaxe_Selection_Arrow then Pickaxe_Selection_Arrow.Visible = visible end
        if not visible then
            for _, item in ipairs(Pickaxe_Selection_Items) do
                item.Box.Visible = false
                item.Text.Visible = false
            end
        end
    end
    if Minimum_value then
        Minimum_value.Visible = visible
    end
    if Minimum_Value_Selection then
        Minimum_Value_Selection.Visible = visible
        if Minimum_Value_Selection_Knob then Minimum_Value_Selection_Knob.Visible = visible end
        if Minimum_Value_Selection_ValueText then Minimum_Value_Selection_ValueText.Visible = visible end
    end
    if Message then
        Message.Visible = visible
    end
    if Message2 then
        Message2.Visible = visible
    end
    if Render_Distance then
        Render_Distance.Visible = visible
    end
    if Render_Distance_Selection then
        Render_Distance_Selection.Visible = visible
        if Render_Distance_Selection_Knob then Render_Distance_Selection_Knob.Visible = visible end
        if Render_Distance_Selection_ValueText then Render_Distance_Selection_ValueText.Visible = visible end
    end
    if Teleports then
        Teleports.Visible = visible
    end
    if Plot_Teleport then
        Plot_Teleport.Visible = visible
        if Plot_Teleport_Text then Plot_Teleport_Text.Visible = visible end
    end
    if Shop_Teleport then
        Shop_Teleport.Visible = visible
        if Shop_Teleport_Text then Shop_Teleport_Text.Visible = visible end
    end
    if Mine_Teleport then
        Mine_Teleport.Visible = visible
        if Mine_Teleport_Text then Mine_Teleport_Text.Visible = visible end
    end
    if Hide_The_Ui then
        Hide_The_Ui.Visible = visible
    end
    if Keybind_To_Hide then
        Keybind_To_Hide.Visible = visible
        if Keybind_To_Hide_Text then Keybind_To_Hide_Text.Visible = visible end
    end
end

-- Input Handling
local dragging = nil
local dragStart = nil
local startPos = nil
local knobStartPos = nil
local lastMouse1 = false

while true do
    wait(0.01)
    if isrbxactive() then
        local mouse1 = ismouse1pressed()
        local mPos = Vector2.new(Mouse.X, Mouse.Y)

        -- Keybind Listeners
        if Keybind_To_Hide_IsListening then
             for i = 1, 255 do
                 if iskeypressed(i) and not ismouse1pressed() then -- Avoid mouse clicks registering as keys if shared ID
                     Keybind_To_Hide_Key = i
                     Keybind_To_Hide_IsListening = false
                     local keyName = KeyNames[i] or "Unknown"
                     Keybind_To_Hide_Text.Text = "[ " .. keyName .. " ]"
                     Keybind_To_Hide_Text.Color = Color3.fromHex("#ffffff")
                     pcall(function() onKeyChanged(i) end)
                     wait(0.2) -- Prevent immediate trigger
                     break
                 end
             end
        else
             if iskeypressed(Keybind_To_Hide_Key) then
                 -- Intelligent Action
                 local newState = not Main_window.Visible
                 Main_window.Visible = newState
                 Title.Visible = newState
                 Title_Background.Visible = newState
                 Pickaxe_Selection.Visible = newState
                 Pickaxe_Selection_Text.Visible = newState
                 Pickaxe_Selection_Arrow.Visible = newState
                 Pickaxe.Visible = newState
                 Minimum_Value_Selection.Visible = newState
                 Minimum_Value_Selection_Knob.Visible = newState
                 Minimum_Value_Selection_ValueText.Visible = newState
                 Minimum_value.Visible = newState
                 Message.Visible = newState
                 Message2.Visible = newState
                 Render_Distance.Visible = newState
                 Render_Distance_Selection.Visible = newState
                 Render_Distance_Selection_Knob.Visible = newState
                 Render_Distance_Selection_ValueText.Visible = newState
                 Plot_Teleport.Visible = newState
                 Plot_Teleport_Text.Visible = newState
                 Shop_Teleport.Visible = newState
                 Shop_Teleport_Text.Visible = newState
                 Mine_Teleport.Visible = newState
                 Mine_Teleport_Text.Visible = newState
                 Teleports.Visible = newState
                 Keybind_To_Hide.Visible = newState
                 Keybind_To_Hide_Text.Visible = newState
                 Hide_The_Ui.Visible = newState
                 wait(0.2) -- Debounce
             end
        end

        -- Mouse Down (Just Pressed)
        if mouse1 and not lastMouse1 then
            -- Button Pickaxe_Selection
            if Pickaxe_Selection.Visible and mPos.X >= Pickaxe_Selection.Position.X and mPos.X <= Pickaxe_Selection.Position.X + Pickaxe_Selection.Size.X and
               mPos.Y >= Pickaxe_Selection.Position.Y and mPos.Y <= Pickaxe_Selection.Position.Y + Pickaxe_Selection.Size.Y then
                pcall(function() onChanged() end)
                -- Toggle Dropdown
                local isOpen = Pickaxe_Selection_Items[1].Box.Visible
                for _, item in ipairs(Pickaxe_Selection_Items) do
                    item.Box.Visible = not isOpen
                    item.Text.Visible = not isOpen
                end
            end
            -- Dropdown Items for Pickaxe_Selection
            if Pickaxe_Selection_Items[1].Box.Visible then
                for _, item in ipairs(Pickaxe_Selection_Items) do
                    if mPos.X >= item.Box.Position.X and mPos.X <= item.Box.Position.X + item.Box.Size.X and
                       mPos.Y >= item.Box.Position.Y and mPos.Y <= item.Box.Position.Y + item.Box.Size.Y then
                        Pickaxe_Selection_Text.Text = item.Value
                        -- Close Dropdown
                        for _, it in ipairs(Pickaxe_Selection_Items) do
                            it.Box.Visible = false
                            it.Text.Visible = false
                        end
                        if onChanged then pcall(function() onChanged(item.Value) end) end
                    end
                end
            end
           -- Button Plot_Teleport
  if Plot_Teleport.Visible and mPos.X >= Plot_Teleport.Position.X and mPos.X <= Plot_Teleport.Position.X + Plot_Teleport.Size.X and
  mPos.Y >= Plot_Teleport.Position.Y and mPos.Y <= Plot_Teleport.Position.Y + Plot_Teleport.Size.Y then
      local lp = game:GetService("Players").LocalPlayer
      local plotId = lp:GetAttribute("PlotId")
      if plotId then
          local plotsFolder = workspace:FindFirstChild("Plots")
          if plotsFolder then
              local myPlot = plotsFolder:FindFirstChild(tostring(plotId))
              if myPlot then
                  local centre = myPlot:FindFirstChild("Centre")
                  local char = lp.Character
                  if centre and char and char:FindFirstChild("HumanoidRootPart") then
                      char.HumanoidRootPart.Position = centre.Position
                  end
              end
          end
      end
  end
  
  -- Button Shop_Teleport
  if Shop_Teleport.Visible and mPos.X >= Shop_Teleport.Position.X and mPos.X <= Shop_Teleport.Position.X + Shop_Teleport.Size.X and
  mPos.Y >= Shop_Teleport.Position.Y and mPos.Y <= Shop_Teleport.Position.Y + Shop_Teleport.Size.Y then
      local lp = game:GetService("Players").LocalPlayer
      local char = lp.Character
      if char and char:FindFirstChild("HumanoidRootPart") then
          char.HumanoidRootPart.Position = Vector3.new(-1550, 10, 20)
      end
  end
  
  -- Button Mine_Teleport
  if Mine_Teleport.Visible and mPos.X >= Mine_Teleport.Position.X and mPos.X <= Mine_Teleport.Position.X + Mine_Teleport.Size.X and
  mPos.Y >= Mine_Teleport.Position.Y and mPos.Y <= Mine_Teleport.Position.Y + Mine_Teleport.Size.Y then
      local lp = game:GetService("Players").LocalPlayer
      local char = lp.Character
      if char and char:FindFirstChild("HumanoidRootPart") then
          char.HumanoidRootPart.Position = Vector3.new(-1889, 7, -193)
      end
  end
            -- Button Keybind_To_Hide
            if Keybind_To_Hide.Visible and mPos.X >= Keybind_To_Hide.Position.X and mPos.X <= Keybind_To_Hide.Position.X + Keybind_To_Hide.Size.X and
               mPos.Y >= Keybind_To_Hide.Position.Y and mPos.Y <= Keybind_To_Hide.Position.Y + Keybind_To_Hide.Size.Y then
                pcall(function() onKeyChanged() end)
                -- Keybind Click
                Keybind_To_Hide_IsListening = true
                Keybind_To_Hide_Text.Text = "..."
                Keybind_To_Hide_Text.Color = Color3.fromHex("#FFFF00")
            end
            -- Drag Main_window
            if Main_window.Visible and mPos.X >= Main_window.Position.X and mPos.X <= Main_window.Position.X + Main_window.Size.X and
               mPos.Y >= Main_window.Position.Y and mPos.Y <= Main_window.Position.Y + Main_window.Size.Y then
                dragging = Main_window
                dragStart = mPos
                startPos = Main_window.Position
            end
            -- Drag Minimum_Value_Selection
            if Minimum_Value_Selection_Knob.Visible and mPos.X >= Minimum_Value_Selection_Knob.Position.X and mPos.X <= Minimum_Value_Selection_Knob.Position.X + Minimum_Value_Selection_Knob.Size.X and
               mPos.Y >= Minimum_Value_Selection_Knob.Position.Y and mPos.Y <= Minimum_Value_Selection_Knob.Position.Y + Minimum_Value_Selection_Knob.Size.Y then
                dragging = Minimum_Value_Selection_Knob
                dragStart = mPos
                startPos = Minimum_Value_Selection_Knob.Position
            end
            -- Drag Render_Distance_Selection
            if Render_Distance_Selection_Knob.Visible and mPos.X >= Render_Distance_Selection_Knob.Position.X and mPos.X <= Render_Distance_Selection_Knob.Position.X + Render_Distance_Selection_Knob.Size.X and
               mPos.Y >= Render_Distance_Selection_Knob.Position.Y and mPos.Y <= Render_Distance_Selection_Knob.Position.Y + Render_Distance_Selection_Knob.Size.Y then
                dragging = Render_Distance_Selection_Knob
                dragStart = mPos
                startPos = Render_Distance_Selection_Knob.Position
            end
        end

        -- Mouse Up (Just Released)
        if not mouse1 and lastMouse1 then
            dragging = nil
        end

        -- Dragging Update
        if dragging and mouse1 then
            local delta = mPos - dragStart
            dragging.Position = startPos + delta
            if dragging == Minimum_Value_Selection_Knob then
                -- Constrain to track
                local minX = Minimum_Value_Selection.Position.X
                local maxX = Minimum_Value_Selection.Position.X + Minimum_Value_Selection.Size.X
                if dragging.Position.X < minX then dragging.Position = Vector2.new(minX, dragging.Position.Y) end
                if dragging.Position.X > maxX then dragging.Position = Vector2.new(maxX, dragging.Position.Y) end
                dragging.Position = Vector2.new(dragging.Position.X, Minimum_Value_Selection.Position.Y + 5 - dragging.Size.Y/2)
                -- Calculate Value
                local percent = (dragging.Position.X - minX) / (Minimum_Value_Selection.Size.X)
                local value = 0 + (15000 - 0) * percent
                Minimum_Value_Selection_Value = value
                Minimum_Value_Selection_ValueText.Text = tostring(math.floor(value)) .. "$"
                pcall(function() onChanged(value) end)
            end
            if dragging == Render_Distance_Selection_Knob then
                -- Constrain to track
                local minX = Render_Distance_Selection.Position.X
                local maxX = Render_Distance_Selection.Position.X + Render_Distance_Selection.Size.X
                if dragging.Position.X < minX then dragging.Position = Vector2.new(minX, dragging.Position.Y) end
                if dragging.Position.X > maxX then dragging.Position = Vector2.new(maxX, dragging.Position.Y) end
                dragging.Position = Vector2.new(dragging.Position.X, Render_Distance_Selection.Position.Y + 5 - dragging.Size.Y/2)
                -- Calculate Value
                local percent = (dragging.Position.X - minX) / (Render_Distance_Selection.Size.X)
                local value = 0 + (30000 - 0) * percent
                Render_Distance_Selection_Value = value
                Render_Distance_Selection_ValueText.Text = tostring(math.floor(value)) .. ""
                pcall(function() onChanged(value) end)
            end
            if dragging == Main_window then
                Title.Position = dragging.Position + Vector2.new(97, 0)
                Title_Background.Position = dragging.Position + Vector2.new(0, 0)
                Pickaxe.Position = dragging.Position + Vector2.new(38, 45)
                Pickaxe_Selection.Position = dragging.Position + Vector2.new(8, 67)
                Pickaxe_Selection_Text.Position = Pickaxe_Selection.Position + Vector2.new(5, 2.5)
                Pickaxe_Selection_Arrow.Position = Pickaxe_Selection.Position + Vector2.new(134 - 20, 2.5)
                for i, item in ipairs(Pickaxe_Selection_Items) do
                    item.Box.Position = Pickaxe_Selection.Position + Vector2.new(0, 24 * i)
                    item.Text.Position = item.Box.Position + Vector2.new(5, 2.5)
                end
                Minimum_value.Position = dragging.Position + Vector2.new(179, 115)
                Minimum_Value_Selection.Position = dragging.Position + Vector2.new(21.5, 162)
                local percent = (Minimum_Value_Selection_Value - 0) / (15000 - 0)
                Minimum_Value_Selection_Knob.Position = Minimum_Value_Selection.Position + Vector2.new(464 * percent - 10, 5 - 10)
                Minimum_Value_Selection_ValueText.Position = Minimum_Value_Selection.Position + Vector2.new(464/2, -10)
                Message.Position = dragging.Position + Vector2.new(251, 179)
                Message2.Position = dragging.Position + Vector2.new(46, 202)
                Render_Distance.Position = dragging.Position + Vector2.new(151, 226)
                Render_Distance_Selection.Position = dragging.Position + Vector2.new(21.5, 267)
                local percent = (Render_Distance_Selection_Value - 0) / (30000 - 0)
                Render_Distance_Selection_Knob.Position = Render_Distance_Selection.Position + Vector2.new(464 * percent - 10, 5 - 10)
                Render_Distance_Selection_ValueText.Position = Render_Distance_Selection.Position + Vector2.new(464/2, -10)
                Teleports.Position = dragging.Position + Vector2.new(302, 45)
                Plot_Teleport.Position = dragging.Position + Vector2.new(180, 68.5)
                Plot_Teleport_Text.Position = Plot_Teleport.Position + Vector2.new(104/2, 21/2)
                Shop_Teleport.Position = dragging.Position + Vector2.new(396, 68.5)
                Shop_Teleport_Text.Position = Shop_Teleport.Position + Vector2.new(104/2, 21/2)
                Mine_Teleport.Position = dragging.Position + Vector2.new(288, 68.5)
                Mine_Teleport_Text.Position = Mine_Teleport.Position + Vector2.new(104/2, 21/2)
                Hide_The_Ui.Position = dragging.Position + Vector2.new(187, 285)
                Keybind_To_Hide.Position = dragging.Position + Vector2.new(186.5, 309)
                Keybind_To_Hide_Text.Position = Keybind_To_Hide.Position + Vector2.new(134/2, 14/2)
            end
