local rs = game:GetService("RunService")

local picks = {
    {n = "Rusty", s = 7}, {n = "Copper", s = 12}, {n = "Iron", s = 20},
    {n = "Steel", s = 35}, {n = "Platinum", s = 60}, {n = "Titanium", s = 100},
    {n = "Infernum", s = 200}, {n = "Diamond", s = 400}, {n = "Mithril", s = 600},
    {n = "Adamantium", s = 800}, {n = "Unobtainium", s = 1000}
}

local ores = {
    Tin = {v = 10, r = 6}, Iron = {v = 20, r = 6}, Lead = {v = 30, r = 7},
    Cobalt = {v = 50, r = 12}, Aluminium = {v = 65, r = 18}, Silver = {v = 150, r = 18},
    Uranium = {v = 180, r = 18}, Vanadium = {v = 240, r = 22}, Tungsten = {v = 300, r = 45},
    Gold = {v = 350, r = 22}, Titanium = {v = 400, r = 24}, Molybdenum = {v = 600, r = 75},
    Plutonium = {v = 1000, r = 99}, Palladium = {v = 1200, r = 120}, Mithril = {v = 2000, r = 200},
    Thorium = {v = 3200, r = 270}, Iridium = {v = 3700, r = 180}, Adamantium = {v = 4500, r = 300},
    Rhodium = {v = 15000, r = 300}, Unobtainium = {v = 30000, r = 340},
    Topaz = {v = 75, r = 6}, Emerald = {v = 200, r = 14}, Sapphire = {v = 250, r = 14},
    Ruby = {v = 300, r = 18}, Diamond = {v = 1500, r = 22}, Poudretteite = {v = 1700, r = 75},
    Zultanite = {v = 2300, r = 110}, Grandidierite = {v = 4500, r = 120}, Musgravite = {v = 5800, r = 150},
    Painite = {v = 12000, r = 200}
}

local activeOres = {}
local cache = {}

-- Función auxiliar para obtener la fuerza del pico actual según la UI
local function getCurrentPickaxeStrength()
    local currentName = Pickaxe_Selection_Text.Text
    for _, p in ipairs(picks) do
        if p.n == currentName then return p.s end
    end
    return 7 -- Por defecto Rusty
end

-- Bucle asíncrono para escanear minerales en el Workspace
spawn(function()
    while true do
        local folder = workspace:FindFirstChild("PlacedOre")
        local char = lp.Character
        if folder and char and char:FindFirstChild("HumanoidRootPart") then
            local myPos = char.HumanoidRootPart.Position
            local strength = getCurrentPickaxeStrength()
            local minPrice = Minimum_Value_Selection_Value
            local maxD = Render_Distance_Selection_Value
            local list = {}

            for _, ore in pairs(folder:GetChildren()) do
                if ore:IsA("MeshPart") then
                    local dist = (ore.Position - myPos).Magnitude
                    if dist <= maxD then
                        local mId = ore:GetAttribute("MineId")
                        if mId and ores[mId] then
                            local d = ores[mId]
                            if strength >= d.r and d.v >= minPrice then
                                table.insert(list, {obj = ore, data = d})
                            end
                        end
                    end
                end
            end
            activeOres = list
        end
        task.wait(1)
    end
end)

-- Bucle de renderizado del ESP
rs.RenderStepped:Connect(function()
    -- Validar si la UI está visible para mostrar/ocultar los textos si lo deseas.
    -- (Opcional: puedes agregar `if not Main_window.Visible then...` para apagar el ESP junto con la UI)
    
    local rendered = {}
    local strength = getCurrentPickaxeStrength()

    for _, item in pairs(activeOres) do
        local obj = item.obj
        local d = item.data
        if obj and obj.Parent then
            local pos, onScreen = WorldToScreen(obj.Position)
            if onScreen then
                if not cache[obj] then
                    local txt = Drawing.new("Text")
                    txt.Size = 14
                    txt.Center = true
                    txt.Outline = true
                    cache[obj] = txt
                end
                
                local txt = cache[obj]
                txt.Visible = true
                txt.Position = pos
                txt.Text = obj:GetAttribute("MineId") .. " [$" .. d.v .. "]"
                
                -- Cambia a rojo si apenas puedes minarlo, verde si es fácil
                if d.r >= strength * 0.8 then
                    txt.Color = Color3.fromRGB(255, 30, 30)
                else
                    txt.Color = Color3.fromRGB(30, 255, 30)
                end
                rendered[obj] = true
            end
        end
    end

    -- Limpiar textos en caché que ya no están en pantalla o fueron minados
    for obj, txt in pairs(cache) do
        if not rendered[obj] then
            txt.Visible = false
            if not obj or not obj.Parent then
                txt:Remove()
                cache[obj] = nil
            end
        end
    end
end)
        
        lastMouse1 = mouse1
    end
end
